    "path": "ShinyAspNet.csproj",
    "content": "<Project Sdk=\"Microsoft.NET.Sdk.Web\">\n\n    <PropertyGroup>\n        <TargetFramework>{DOTNET_TFM}</TargetFramework>\n        <Nullable>enable</Nullable>\n        <ImplicitUsings>enable</ImplicitUsings>\n        <OpenApiDocumentsDirectory>.</OpenApiDocumentsDirectory>\n        <MicrosoftVersion>10.0.8</MicrosoftVersion>\n        <ShinyExtensionsLocalizationVersion>2.0.1</ShinyExtensionsLocalizationVersion>\n        <ShinyExtensionsReflectorVersion>5.0.0</ShinyExtensionsReflectorVersion>\n        <ShinyExtensionsDIVersion>5.0.0</ShinyExtensionsDIVersion>\n        <ShinyExtensionsWebHostingVersion>5.0.0</ShinyExtensionsWebHostingVersion>\n        <ShinyDocumentDbVersion>6.1.0</ShinyDocumentDbVersion>\n        <MediatorVersion>6.6.1</MediatorVersion>\n        <ScalarVersion>2.16.2</ScalarVersion>\n        <!--#if (orleans)-->\n        <OrleansVersion>10.1.0</OrleansVersion>\n        <!--#endif-->\n    </PropertyGroup>\n\n    <ItemGroup>\n        <PackageReference Include=\"Microsoft.AspNetCore.OpenApi\" Version=\"$(MicrosoftVersion)\" />\n        <PackageReference Include=\"Microsoft.Extensions.ApiDescription.Server\" Version=\"$(MicrosoftVersion)\"/>\n        <PackageReference Include=\"Shiny.Extensions.DependencyInjection\" Version=\"$(ShinyExtensionsDIVersion)\"/>\n        <PackageReference Include=\"Shiny.Extensions.WebHosting\" Version=\"$(ShinyExtensionsWebHostingVersion)\" />\n\n        <!--#if (localization)-->\n        <PackageReference Include=\"Shiny.Extensions.Localization.Generator\" Version=\"$(ShinyExtensionsLocalizationVersion)\" />\n        <!--#endif-->\n\n        <!--#if (reflector)-->\n        <PackageReference Include=\"Shiny.Extensions.Reflector\" Version=\"$(ShinyExtensionsReflectorVersion)\" />\n        <!--#endif-->\n\n        <!--#if (efmssql)-->\n        <PackageReference Include=\"Microsoft.EntityFrameworkCore.SqlServer\" Version=\"$(MicrosoftVersion)\" />\n        <!--#if (efspatial)-->\n        <PackageReference Include=\"Microsoft.EntityFrameworkCore.SqlServer.NetTopologySuite\" Version=\"$(MicrosoftVersion)\" />\n        <!--#endif-->\n        <!--#endif-->\n\n        <!--#if (efpostgres)-->\n        <PackageReference Include=\"Npgsql.EntityFrameworkCore.PostgreSQL\" Version=\"$(MicrosoftVersion)\" />\n        <!--#if (efspatial)-->\n        <PackageReference Include=\"Npgsql.EntityFrameworkCore.PostgreSQL.NetTopologySuite\" Version=\"$(MicrosoftVersion)\" />\n        <!--#endif-->\n        <!--#endif-->\n\n        <!--#if (docdbsqlite)-->\n        <PackageReference Include=\"Shiny.DocumentDb.Sqlite\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdbsqlcipher)-->\n        <PackageReference Include=\"Shiny.DocumentDb.Sqlite.SqlCipher\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdbsqlserver)-->\n        <PackageReference Include=\"Shiny.DocumentDb.SqlServer\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdbmysql)-->\n        <PackageReference Include=\"Shiny.DocumentDb.MySql\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdbpostgres)-->\n        <PackageReference Include=\"Shiny.DocumentDb.PostgreSql\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdbcosmos)-->\n        <PackageReference Include=\"Shiny.DocumentDb.CosmosDb\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdbmongo)-->\n        <PackageReference Include=\"Shiny.DocumentDb.MongoDb\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdblitedb)-->\n        <PackageReference Include=\"Shiny.DocumentDb.LiteDb\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (docdbduckdb)-->\n        <PackageReference Include=\"Shiny.DocumentDb.DuckDb\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n        <!--#if (aidocumentdb)-->\n        <PackageReference Include=\"Shiny.DocumentDb.Extensions.AI\" Version=\"$(ShinyDocumentDbVersion)\" />\n        <!--#endif-->\n\n        <!--#if (orleans)-->\n        <PackageReference Include=\"Microsoft.Orleans.Server\" Version=\"$(OrleansVersion)\" />\n        <PackageReference Include=\"Microsoft.Orleans.Sdk\" Version=\"$(OrleansVersion)\" />\n        <PackageReference Include=\"Microsoft.Orleans.BroadcastChannel\" Version=\"$(OrleansVersion)\" />\n        <PackageReference Include=\"Microsoft.Orleans.Hosting.Kubernetes\" Version=\"$(OrleansVersion)\"/>\n        <PackageReference Include=\"Microsoft.Orleans.Clustering.AdoNet\" Version=\"$(OrleansVersion)\"/>\n        <PackageReference Include=\"Microsoft.Orleans.Persistence.AdoNet\" Version=\"$(OrleansVersion)\"/>\n        <PackageReference Include=\"Microsoft.Orleans.Reminders\" Version=\"$(OrleansVersion)\"/>\n        <PackageReference Include=\"Microsoft.Orleans.Reminders.AdoNet\" Version=\"$(OrleansVersion)\" />\n        <PackageReference Include=\"Microsoft.Orleans.Streaming\" Version=\"$(OrleansVersion)\"/>\n        <PackageReference Include=\"Microsoft.Orleans.Streaming.AdoNet\" Version=\"$(OrleansVersion)-alpha.1\" />\n        <PackageReference Include=\"Microsoft.Orleans.Dashboard\" Version=\"$(OrleansVersion)\" />\n        <!--#endif-->\n\n        <!--#if (jwtauth)-->\n        <PackageReference Include=\"Microsoft.AspNetCore.Authentication.JwtBearer\" Version=\"$(MicrosoftVersion)\" />\n        <!--#endif-->\n        <!--#if (facebook)-->\n        <PackageReference Include=\"Microsoft.AspNetCore.Authentication.Facebook\" Version=\"$(MicrosoftVersion)\" />\n        <!--#endif-->\n        <!--#if (google)-->\n        <PackageReference Include=\"Microsoft.AspNetCore.Authentication.Google\" Version=\"$(MicrosoftVersion)\" />\n        <!--#endif-->\n        <!--#if (apple)-->\n        <PackageReference Include=\"AspNet.Security.OAuth.Apple\" Version=\"10.0.0\" />\n        <!--#endif-->\n\n        <!--#if (usemediator)-->\n        <PackageReference Include=\"Shiny.Mediator.AspNet\" Version=\"$(MediatorVersion)\" />\n        <!--#endif-->\n        <!--#if (scalar)-->\n        <PackageReference Include=\"Scalar.AspNetCore\" Version=\"$(ScalarVersion)\"/>\n        <!--#endif-->\n    </ItemGroup>\n</Project>\n"
